17	AbcSegmentor::AbcSegmentor(const Ticket& ticket)
18	    : Segmentor(ticket), alphabet_(kRimeAlphabet) {
19	  if (!ticket.schema)
20	    return;
21	  if (Config* config = ticket.schema->config()) {
22	    config->GetString("speller/alphabet", &alphabet_);
23	    config->GetString("speller/delimiter", &delimiter_);
24	    config->GetString("speller/initials", &initials_);
25	    config->GetString("speller/finals", &finals_);
26	    if (auto extra_tags = config->GetList("abc_segmentor/extra_tags")) {
27	      for (size_t i = 0; i < extra_tags->size(); ++i) {
28	        if (auto value = As<ConfigValue>(extra_tags->GetAt(i))) {
29	          extra_tags_.insert(value->str());
30	        }
31	      }
32	    }
33	  }
34	  if (initials_.empty()) {
35	    initials_ = alphabet_;
36	  }
37	}
38	
39	bool AbcSegmentor::Proceed(Segmentation* segmentation) {
40	  const string& input(segmentation->input());
41	  DLOG(INFO) << "abc_segmentor: " << input;
42	  size_t j = segmentation->GetCurrentStartPosition();
43	  size_t k = j;
44	  bool expecting_an_initial = true;
45	  for (; k < input.length(); ++k) {
46	    bool is_letter = alphabet_.find(input[k]) != string::npos;
47	    bool is_delimiter = (k != 0) && (delimiter_.find(input[k]) != string::npos);
48	    if (!is_letter && !is_delimiter)
49	      break;
50	    bool is_initial = initials_.find(input[k]) != string::npos;
51	    bool is_final = finals_.find(input[k]) != string::npos;
52	    if (expecting_an_initial && !is_initial && !is_delimiter) {
53	      break;  // not a valid spelling.
54	    }
55	    // for the next character.
56	    expecting_an_initial = is_final || is_delimiter;
57	  }
58	  DLOG(INFO) << "[" << j << ", " << k << ")";
59	  if (j < k) {
60	    Segment segment(j, k);
61	    segment.tags.insert("abc");
62	    for (const string& tag : extra_tags_) {
63	      segment.tags.insert(tag);
64	    }
65	    segmentation->AddSegment(segment);
66	  }
67	  // continue this round
68	  return true;
69	}
