14	    : Segmentor(ticket) {}
15	
16	bool FallbackSegmentor::Proceed(Segmentation* segmentation) {
17	  int len = segmentation->GetCurrentSegmentLength();
18	  DLOG(INFO) << "current segment length: " << len;
19	  if (len > 0)
20	    return false;
21	
22	  const string& input(segmentation->input());
23	  int k = segmentation->GetCurrentStartPosition();
24	  DLOG(INFO) << "current start pos: " << k;
25	  if (k == input.length())
26	    return false;
27	
28	  DLOG(INFO) << "segmentation: " << *segmentation;
29	  if (!segmentation->empty() &&
30	      segmentation->back().start == segmentation->back().end) {
31	    segmentation->pop_back();
32	  }
33	
34	  if (!segmentation->empty()) {
35	    Segment& last(segmentation->back());
36	    // append one character to the last raw segment
37	    if (last.HasTag("raw")) {
38	      last.end = k + 1;
39	      DLOG(INFO) << "extend previous raw segment to [" << last.start << ", "
40	                 << last.end << ")";
41	      // mark redo translation (in case it's been previously translated)
42	      last.Clear();
43	      last.tags.insert("raw");
44	      return false;
45	    }
46	  }
47	  {
48	    Segment segment(k, k + 1);
49	    DLOG(INFO) << "add a raw segment [" << segment.start << ", " << segment.end
50	               << ")";
51	    segment.tags.insert("raw");
52	    segmentation->Forward();
53	    segmentation->AddSegment(segment);
54	  }
55	  // fallback segmentor should be the last being called, so end this round
56	  return false;
57	}
