33	static CandidateList::iterator find_text_match(const an<Candidate>& target,
34	                                               CandidateList::iterator begin,
35	                                               CandidateList::iterator end) {
36	  for (auto iter = begin; iter != end; ++iter) {
37	    if ((*iter)->text() == target->text()) {
38	      return iter;
39	    }
40	  }
41	  return end;
42	}
43	
44	bool UniquifiedTranslation::Uniquify() {
45	  while (!exhausted()) {
46	    auto next = Peek();
47	    CandidateList::iterator previous =
48	        find_text_match(next, candidates_->begin(), candidates_->end());
49	    if (previous == candidates_->end()) {
50	      // Encountered a unique candidate.
51	      return true;
52	    }
53	    auto uniquified = As<UniquifiedCandidate>(*previous);
54	    if (!uniquified) {
55	      *previous = uniquified =
56	          New<UniquifiedCandidate>(*previous, "uniquified");
57	    }
58	    uniquified->Append(next);
59	    CacheTranslation::Next();
60	  }
61	  return false;
62	}
