18	bool is_extended_cjk(uint32_t ch) {
19	  if ((ch >= 0x3400 && ch <= 0x4DBF) ||    // CJK Unified Ideographs Extension A
20	      (ch >= 0x20000 && ch <= 0x2A6DF) ||  // CJK Unified Ideographs Extension B
21	      (ch >= 0x2A700 && ch <= 0x2B73F) ||  // CJK Unified Ideographs Extension C
22	      (ch >= 0x2B740 && ch <= 0x2B81F) ||  // CJK Unified Ideographs Extension D
23	      (ch >= 0x2B820 && ch <= 0x2CEAF) ||  // CJK Unified Ideographs Extension E
24	      (ch >= 0x2CEB0 && ch <= 0x2EBEF) ||  // CJK Unified Ideographs Extension F
25	      (ch >= 0x30000 && ch <= 0x3134F) ||  // CJK Unified Ideographs Extension G
26	      (ch >= 0x31350 && ch <= 0x323AF) ||  // CJK Unified Ideographs Extension H
27	      (ch >= 0x2EBF0 && ch <= 0x2EE5F) ||  // CJK Unified Ideographs Extension I
28	      (ch >= 0x323B0 && ch <= 0x3347F) ||  // CJK Unified Ideographs Extension J
29	      // (ch >= 0x3300 && ch <= 0x33FF) ||  // CJK Compatibility
30	      // (ch >= 0xFE30 && ch <= 0xFE4F) ||  // CJK Compatibility Forms
31	      (ch >= 0xF900 && ch <= 0xFAFF) ||  // CJK Compatibility Ideographs
32	      (ch >= 0x2F800 &&
33	       ch <= 0x2FA1F))  // CJK Compatibility Ideographs Supplement
34	    return true;
35	
36	  return false;
37	}
38	
39	bool contains_extended_cjk(const string& text) {
40	  const char* p = text.c_str();
41	  uint32_t ch;
42	
43	  while ((ch = utf8::unchecked::next(p)) != 0) {
44	    if (is_extended_cjk(ch)) {
45	      return true;
46	    }
47	  }
48	
49	  return false;
50	}
