32	
33	bool SingleCharFirstTranslation::Rearrange() {
34	  if (exhausted()) {
35	    return false;
36	  }
37	  CandidateQueue top;
38	  CandidateQueue bottom;
39	  while (!translation_->exhausted()) {
40	    auto cand = translation_->Peek();
41	    auto phrase = As<Phrase>(Candidate::GetGenuineCandidate(cand));
42	    if (!phrase ||
43	        (phrase->type() != "table" && phrase->type() != "user_table")) {
44	      break;
45	    }
46	    if (unistrlen(cand->text()) == 1) {
47	      top.push_back(cand);
48	    } else {
49	      bottom.push_back(cand);
50	    }
51	    translation_->Next();
52	  }
53	  cache_.splice(cache_.end(), top);
54	  cache_.splice(cache_.end(), bottom);
55	  return !cache_.empty();
56	}
