99	bool ConcreteEngine::ProcessKey(const KeyEvent& key_event) {
100	  DLOG(INFO) << "process key: " << key_event;
101	  ProcessResult ret = kNoop;
102	  for (auto& processor : processors_) {
103	    ret = processor->ProcessKeyEvent(key_event);
104	    if (ret == kRejected)
105	      break;
106	    if (ret == kAccepted)
107	      return true;
108	  }
109	  // record unhandled keys, eg. spaces, numbers, bksp's.
110	  context_->commit_history().Push(key_event);
111	  // post-processing
112	  for (auto& processor : post_processors_) {
113	    ret = processor->ProcessKeyEvent(key_event);
114	    if (ret == kRejected)
115	      break;
116	    if (ret == kAccepted)
117	      return true;
118	  }
119	  // notify interested parties
120	  context_->unhandled_key_notifier()(context_.get(), key_event);
121	  return false;
122	}
