154	void ConcreteEngine::Compose(Context* ctx) {
155	  if (!ctx)
156	    return;
157	  Composition& comp = ctx->composition();
158	  const string active_input = ctx->input().substr(0, ctx->caret_pos());
159	  DLOG(INFO) << "active input: " << active_input;
160	  comp.Reset(active_input);
161	  if (ctx->caret_pos() < ctx->input().length() &&
162	      ctx->caret_pos() == comp.GetConfirmedPosition()) {
163	    // translate one segment past caret pos.
164	    comp.Reset(ctx->input());
165	  }
166	  CalculateSegmentation(&comp);
167	  TranslateSegments(&comp);
168	  DLOG(INFO) << "composition: [" << comp.GetDebugText() << "]";
169	}
170	
171	void ConcreteEngine::CalculateSegmentation(Segmentation* segments) {
172	  DLOG(INFO) << "CalculateSegmentation, segments: " << segments->size()
173	             << ", finished? " << segments->HasFinishedSegmentation();
174	  while (!segments->HasFinishedSegmentation()) {
175	    size_t start_pos = segments->GetCurrentStartPosition();
176	    size_t end_pos = segments->GetCurrentEndPosition();
177	    DLOG(INFO) << "start pos: " << start_pos;
178	    DLOG(INFO) << "end pos: " << end_pos;
179	    // recognize a segment by calling the segmentors in turn
180	    for (auto& segmentor : segmentors_) {
181	      if (!segmentor->Proceed(segments))
182	        break;
183	    }
184	    DLOG(INFO) << "segmentation: " << *segments;
185	    // no advancement
186	    if (start_pos == segments->GetCurrentEndPosition())
187	      break;
188	    // only one segment is allowed past caret pos, which is the segment
189	    // immediately after the caret.
190	    if (start_pos >= context_->caret_pos())
191	      break;
192	    // move onto the next segment...
193	    if (!segments->HasFinishedSegmentation())
194	      segments->Forward();
195	  }
196	  // start an empty segment only at the end of a confirmed composition.
197	  if (!segments->empty() && !segments->back().HasTag("placeholder"))
198	    segments->Trim();
199	  if (!segments->empty() && segments->back().status >= Segment::kSelected)
200	    segments->Forward();

200	    segments->Forward();
201	}
202	
203	void ConcreteEngine::TranslateSegments(Segmentation* segments) {
204	  DLOG(INFO) << "TranslateSegments: " << *segments;
205	  for (Segment& segment : *segments) {
206	    DLOG(INFO) << "segment [" << segment.start << ", " << segment.end
207	               << "), status: " << segment.status;
208	    if (segment.status >= Segment::kGuess)
209	      continue;
210	    size_t len = segment.end - segment.start;
211	    string input = segments->input().substr(segment.start, len);
212	    DLOG(INFO) << "translating segment: [" << input << "]";
213	    auto menu = New<Menu>();
214	    for (auto& translator : translators_) {
215	      auto translation = translator->Query(input, segment);
216	      if (!translation)
217	        continue;
218	      if (translation->exhausted()) {
219	        DLOG(INFO) << translator->name_space() << " made a futile translation.";
220	        continue;
221	      }
222	      menu->AddTranslation(translation);
223	    }
224	    for (auto& filter : filters_) {
225	      if (filter->AppliesToSegment(&segment)) {
226	        menu->AddFilter(filter.get());
227	      }
228	    }
229	    segment.status = Segment::kGuess;
230	    segment.menu = menu;
231	    segment.selected_index = 0;
232	  }
233	}
