376	void ConcreteEngine::InitializeOptions() {
377	  LOG(INFO) << "ConcreteEngine::InitializeOptions";
378	  // reset custom switches
379	  Config* config = schema_->config();
380	  Switches switches(config);
381	  switches.FindOption([this](Switches::SwitchOption option) {
382	    LOG(INFO) << "found switch option: " << option.option_name
383	              << ", reset: " << option.reset_value;
384	    if (option.reset_value >= 0) {
385	      if (option.type == Switches::kToggleOption) {
386	        context_->set_option(option.option_name, (option.reset_value != 0));
387	      } else if (option.type == Switches::kRadioGroup) {
388	        context_->set_option(
389	            option.option_name,
390	            static_cast<int>(option.option_index) == option.reset_value);
391	      }
392	    }
393	    return Switches::kContinue;
394	  });
395	}
