26	size_t Menu::Prepare(size_t requested) {
27	  DLOG(INFO) << "preparing " << requested << " candidates.";
28	  while (candidates_.size() < requested && !result_->exhausted()) {
29	    if (auto cand = result_->Peek()) {
30	      candidates_.push_back(cand);
31	    }
32	    result_->Next();
33	  }
34	  return candidates_.size();
35	}
36	
37	Page* Menu::CreatePage(size_t page_size, size_t page_no) {
38	  size_t start_pos = page_size * page_no;
39	  size_t end_pos = start_pos + page_size;
40	  if (end_pos > candidates_.size()) {
41	    if (result_->exhausted())
42	      end_pos = candidates_.size();
43	    else
44	      end_pos = Prepare(end_pos);
45	    if (start_pos >= end_pos)
46	      return NULL;
47	    end_pos = (std::min)(start_pos + page_size, end_pos);
48	  }
49	  Page* page = new Page;
50	  if (!page)
51	    return NULL;
52	  page->page_size = page_size;
53	  page->page_no = page_no;
54	  page->is_last_page = result_->exhausted() && (end_pos == candidates_.size());
55	  std::copy(candidates_.begin() + start_pos, candidates_.begin() + end_pos,
56	            std::back_inserter(page->candidates));
57	  return page;
58	}
59	
60	an<Candidate> Menu::GetCandidateAt(size_t index) {
61	  if (index >= candidates_.size() && index >= Prepare(index + 1)) {
62	    return nullptr;
63	  }
64	  return candidates_[index];
65	}
66	
67	bool Menu::empty() const {
68	  return candidates_.empty() && result_->exhausted();
69	}
